const fs = require('fs');

// Load the template (mounted into container at /prompts/)
const template = fs.readFileSync('/prompts/memory-consolidation.md', 'utf-8');

// Group messages by channel_id
const all = $input.all().map(i => i.json);
const byChannel = {};
for (const m of all) {
  byChannel[m.channel_id] = byChannel[m.channel_id] || [];
  byChannel[m.channel_id].push(m);
}

// Build a readable conversations block
const chunks = [];
const channelsContributing = [];
for (const [chan, msgs] of Object.entries(byChannel)) {
  const platform = msgs[0]?.platform || 'unknown';
  channelsContributing.push(`${platform}:${chan}`);
  chunks.push(`## ${platform} — ${chan} (${msgs.length} messages)`);
  for (const m of msgs) {
    const who = m.role === 'assistant' ? 'the agent' : (m.username || 'User');
    const text = String(m.content || '').replace(/\s+/g, ' ').slice(0, 800);
    chunks.push(`${who}: ${text}`);
  }
  chunks.push('');
}

const conversations = chunks.join('\n');
const prompt = template.replace(/\{\{conversations\}\}/g, conversations);

// Yesterday's date ISO for source_date
const d = new Date();
d.setUTCDate(d.getUTCDate() - 1);
const sourceDate = d.toISOString().slice(0, 10);

return [{ json: { prompt, sourceDate, channelsContributing, messageCount: all.length } }];

const result = $input.first().json;
const output = String(result.output || '').trim();
const ctx = $('Build Consolidation Prompt').item.json;

if (output === 'NO_PROPOSALS' || output.startsWith('NO_PROPOSALS')) {
  return [{ json: { skip: true, reason: 'NO_PROPOSALS', sourceDate: ctx.sourceDate, messageCount: ctx.messageCount } }];
}

// Parse blocks of the form:
//   **PROPOSED MEMORY UPDATE:** <name>
//   Type: <type>
//   Body:
//   <body...>
//   Source channels: <csv>
const blocks = output.split(/\n(?=\*\*PROPOSED MEMORY UPDATE:\*\*)/);
const proposals = [];

for (const block of blocks) {
  if (!block.includes('PROPOSED MEMORY UPDATE')) continue;
  const nameMatch = block.match(/\*\*PROPOSED MEMORY UPDATE:\*\*\s*(.+)/);
  const typeMatch = block.match(/Type:\s*(user|feedback|project|reference)/i);
  const bodyMatch = block.match(/Body:\s*\n([\s\S]*?)(?=\n(?:Source channels:|\*\*PROPOSED)|$)/);
  const chanMatch = block.match(/Source channels:\s*(.+)/);

  if (!nameMatch || !typeMatch || !bodyMatch) continue;

  proposals.push({
    suggested_name: nameMatch[1].trim(),
    memory_type: typeMatch[1].toLowerCase(),
    body: bodyMatch[1].trim(),
    source_channels: chanMatch ? chanMatch[1].split(',').map(s => s.trim()) : ctx.channelsContributing,
    source_date: ctx.sourceDate
  });
}

if (proposals.length === 0) {
  return [{ json: { skip: true, reason: 'no blocks parsed from output', sourceDate: ctx.sourceDate, rawOutput: output.slice(0, 500) } }];
}

return proposals.map(p => ({ json: p }));
